    pub data: Option<String>,
    /// Internal weak reference counter.
    pub weak_ref_count: u8,
    /// Validity flag for the weak reference.
    pub weak_ref_node_valid: u8,
}

/// Type alias for a key comparison function.
/// Should return a positive value if `b` is larger than `a`,
/// a negative value if `a` is larger, and zero if equal.
pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;

/// Type alias for a free function which will be called on nodes
/// that are removed.
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

// Helper: max of two u32 values
fn imax(i1: u32, i2: u32) -> u32 {
    if i1 > i2 { i1 } else { i2 }
}

// Helper: compute balance factor (right_depth - left_depth)
fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
    let n = node.borrow();
    let left_depth = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    let right_depth = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
    right_depth as i32 - left_depth as i32
}

// Helper: compute depth from children (reads children depths without holding parent borrow)
fn compute_depth(left: &Option<Rc<RefCell<BOSNode>>>, right: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
    let left_d = left.as_ref().map_or(0, |c| c.borrow().depth + 1);
    let right_d = right.as_ref().map_or(0, |c| c.borrow().depth + 1);
    imax(left_d, right_d)
}

// Helper: check if a node is the left child of its parent
fn is_left_child(node: &Rc<RefCell<BOSNode>>) -> bool {
    let parent_weak = node.borrow().parent_node.clone();
    parent_weak.as_ref().and_then(|pw| pw.upgrade()).map_or(false, |pp| {
        pp.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(node, lc))
    })
}

// Helper: check if a node is the right child of its parent
fn is_right_child(node: &Rc<RefCell<BOSNode>>) -> bool {
    let parent_weak = node.borrow().parent_node.clone();
    parent_weak.as_ref().and_then(|pw| pw.upgrade()).map_or(false, |pp| {
        pp.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(node, rc))
    })
}

// Rotate right:
//      P                     L
//  L        R     -->    c1      P
//c1 c2                        c2     R
fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // Extract all needed info from P first
    let l = p.borrow().left_child_node.clone().unwrap();
    let p_parent = p.borrow().parent_node.clone();
    let p_is_left = is_left_child(p);

    // Update parent's child pointer or tree root
    if let Some(ref pw) = p_parent {
        if let Some(pp) = pw.upgrade() {
            if p_is_left {
                pp.borrow_mut().left_child_node = Some(l.clone());
            } else {
                pp.borrow_mut().right_child_node = Some(l.clone());
            }
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    // L's parent = P's parent
    l.borrow_mut().parent_node = p_parent;

    // P's left child = L's right child
    let l_right = l.borrow().right_child_node.clone();
    let l_right_count = l.borrow().right_child_count;
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l_right_count;
    if let Some(lr) = l_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    // Update P's depth
    {
        let p_ref = p.borrow();
        let new_depth = compute_depth(&p_ref.left_child_node, &p_ref.right_child_node);
        p_ref.depth; // read to release borrow
        p.borrow_mut().depth = new_depth;
    }

    // L's right child = P
    l.borrow_mut().right_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    // L's right_child_count = P's left_child_count + P's right_child_count + 1
    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    l.borrow_mut().right_child_count = p_left_count + p_right_count + 1;

    // Update L's depth
    {
        let l_ref = l.borrow();
        let new_depth = compute_depth(&l_ref.left_child_node, &l_ref.right_child_node);
        l_ref.depth; // read to release borrow
        l.borrow_mut().depth = new_depth;
    }

    l
}

// Rotate left:
//      P                     R
//  L        R     -->    P      c2
//         c1 c2        L  c1
fn rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    // Extract all needed info from P first
    let r = p.borrow().right_child_node.clone().unwrap();
    let p_parent = p.borrow().parent_node.clone();
    let p_is_left = is_left_child(p);

    // Update parent's child pointer or tree root
    if let Some(ref pw) = p_parent {
        if let Some(pp) = pw.upgrade() {
            if p_is_left {
                pp.borrow_mut().left_child_node = Some(r.clone());
            } else {
                pp.borrow_mut().right_child_node = Some(r.clone());
            }
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    // R's parent = P's parent
    r.borrow_mut().parent_node = p_parent;

    // P's right child = R's left child
    let r_left = r.borrow().left_child_node.clone();
    let r_left_count = r.borrow().left_child_count;
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = r_left_count;
    if let Some(rl) = r_left {
        rl.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    // Update P's depth
    {
        let p_ref = p.borrow();
        let new_depth = compute_depth(&p_ref.left_child_node, &p_ref.right_child_node);
        p_ref.depth;
        p.borrow_mut().depth = new_depth;
    }

    // R's left child = P
    r.borrow_mut().left_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    // R's left_child_count = P's left_child_count + P's right_child_count + 1
    let p_left_count = p.borrow().left_child_count;
    let p_right_count = p.borrow().right_child_count;
    r.borrow_mut().left_child_count = p_left_count + p_right_count + 1;

    // Update R's depth
    {
        let r_ref = r.borrow();
        let new_depth = compute_depth(&r_ref.left_child_node, &r_ref.right_child_node);
        r_ref.depth;
        r.borrow_mut().depth = new_depth;
    }

    r
}

impl BOSTree {
    /// Create a new tree with a mandatory comparison function and an optional free function.
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    /// Return the number of nodes in the tree.
    pub fn bostree_node_count(&self) -> u32 {
        match &self.root_node {
            Some(root) => root.borrow().left_child_count + root.borrow().right_child_count + 1,
            None => 0,
        }
    }

    /// Insert a new member into the tree and return the associated node.
    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        // Create the new node
        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: None,
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        let new_key = new_node.borrow().key.clone();

        // Find tree position to insert new node
        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;
        let mut current = self.root_node.clone();

        while let Some(cur) = current.clone() {
            let cmp = (self.cmp_function)(&new_key, &cur.borrow().key);
            parent_node = Some(cur.clone());
            if cmp < 0 {
                cur.borrow_mut().left_child_count += 1;
                current = cur.borrow().left_child_node.clone();
            } else {
                cur.borrow_mut().right_child_count += 1;
                current = cur.borrow().right_child_node.clone();
            }
        }

        // Set the new node's parent
        new_node.borrow_mut().parent_node = parent_node.as_ref().map(|p| Rc::downgrade(p));

        // Attach new node to parent or set as root
        if let Some(ref parent) = parent_node {
            let cmp = (self.cmp_function)(&new_key, &parent.borrow().key);
            if cmp < 0 {
                parent.borrow_mut().left_child_node = Some(new_node.clone());
            } else {
                parent.borrow_mut().right_child_node = Some(new_node.clone());
            }
        } else {
            // Simple case, this is the first node.
            self.root_node = Some(new_node.clone());
            return new_node;
        }

        // Check if the depth changed with the new node:
        // It does only change if this is the first child of the parent
        let parent = parent_node.unwrap();
        let has_left = parent.borrow().left_child_node.is_some();
        let has_right = parent.borrow().right_child_node.is_some();
        let depth_changed = has_left ^ has_right;

        if depth_changed {
            // Bubble the information up the tree
            parent.borrow_mut().depth += 1;

            // We need to track the "current" node as we move up.
            // In C, the loop is: while(parent_node->parent_node) { parent_node = parent_node->parent_node; ... }
            // After rotation, parent_node becomes the new subtree root, and the loop continues.
            let mut current_node = parent;

            while current_node.borrow().parent_node.is_some() {
                // Move up to parent
                let parent_weak = current_node.borrow().parent_node.clone().unwrap();
                let pp = parent_weak.upgrade().unwrap();
                // current_node is no longer needed; we'll work with pp

                let new_left_depth = pp.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let new_right_depth = pp.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let max_depth = imax(new_left_depth, new_right_depth);

                if pp.borrow().depth != max_depth {
                    pp.borrow_mut().depth = max_depth;
                } else {
                    // Depth didn't change, we can stop bubbling
                    break;
                }

                // Check AVL property violation
                if new_left_depth as i32 - 2 == new_right_depth as i32 {
                    // Left is two levels deeper than right. Rotate right.
                    // Handle left-right case first.
                    let left_child = pp.borrow().left_child_node.clone().unwrap();
                    if bostree_balance(&left_child) > 0 {
                        rotate_left(self, &left_child);
                    }
                    current_node = rotate_right(self, &pp);
                } else if new_left_depth as i32 + 2 == new_right_depth as i32 {
                    // Right is two levels deeper than left. Rotate left.
                    // Handle right-left case first.
                    let right_child = pp.borrow().right_child_node.clone().unwrap();
                    if bostree_balance(&right_child) < 0 {
                        rotate_right(self, &right_child);
                    }
                    current_node = rotate_left(self, &pp);
                } else {
                    current_node = pp;
                }
            }
        }

        new_node
    }

    /// Remove a given node from the tree.
    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        let mut bubble_up: Option<Rc<RefCell<BOSNode>>>;

        if has_left && has_right {
            // Node has children on both sides
            let left_depth = node.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth);
            let right_depth = node.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth);

            let candidate;
            let lost_child;
            let bubble_start;

            if left_depth >= right_depth {
                // Left branch is deeper, bubble from this side
                node.borrow_mut().left_child_count -= 1;
                candidate = node.borrow().left_child_node.clone().unwrap();
                // Walk down right side of left subtree
                let mut c = candidate.clone();
                while c.borrow().right_child_node.is_some() {
                    c.borrow_mut().right_child_count -= 1;
                    let next = c.borrow().right_child_node.clone().unwrap();
                    c = next;
                }
                candidate = c.clone();
                lost_child = c.borrow().left_child_node.clone();
                bubble_start = c.borrow().parent_node.clone().and_then(|pw| pw.upgrade()).unwrap();
            } else {
                // Right branch is deeper, bubble from this side
                node.borrow_mut().right_child_count -= 1;
                candidate = node.borrow().right_child_node.clone().unwrap();
                // Walk down left side of right subtree
                let mut c = candidate.clone();
                while c.borrow().left_child_node.is_some() {
                    c.borrow_mut().left_child_count -= 1;
                    let next = c.borrow().left_child_node.clone().unwrap();
                    c = next;
                }
                candidate = c.clone();
                lost_child = c.borrow().right_child_node.clone();
                bubble_start = c.borrow().parent_node.clone().and_then(|pw| pw.upgrade()).unwrap();
            }

            // Remove candidate from its parent (bubble_start)
            let candidate_is_left = is_left_child(&candidate);
            if candidate_is_left {
                bubble_start.borrow_mut().left_child_node = lost_child.clone();
            } else {
                bubble_start.borrow_mut().right_child_node = lost_child.clone();
            }
            if let Some(lc) = lost_child {
                lc.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            // Anchor candidate into the place where "node" used to be
            let node_parent = node.borrow().parent_node.clone();
            let node_is_left = is_left_child(node);

            if let Some(ref pw) = node_parent {
                if let Some(np) = pw.upgrade() {
                    if node_is_left {
                        np.borrow_mut().left_child_node = Some(candidate.clone());
                    } else {
                        np.borrow_mut().right_child_node = Some(candidate.clone());
                    }
                }
            } else {
                self.root_node = Some(candidate.clone());
            }
            candidate.borrow_mut().parent_node = node_parent;

            // Transfer node's children to candidate
            let node_left = node.borrow().left_child_node.clone();
            let node_left_count = node.borrow().left_child_count;
            let node_right = node.borrow().right_child_node.clone();
            let node_right_count = node.borrow().right_child_count;

            candidate.borrow_mut().left_child_node = node_left.clone();
            candidate.borrow_mut().left_child_count = node_left_count;
            candidate.borrow_mut().right_child_node = node_right.clone();
            candidate.borrow_mut().right_child_count = node_right_count;

            if let Some(nl) = node_left {
                nl.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(nr) = node_right {
                nr.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            // Rebalance from bubble_start up to candidate
            // Check if bubble_start != node (they could be the same if candidate was a direct child)
            let node_ptr = node.as_ptr() as usize;
            let bubble_start_ptr = bubble_start.as_ptr() as usize;

            if bubble_start_ptr != node_ptr {
                let mut bs = bubble_start.clone();
                let candidate_ptr = candidate.as_ptr() as usize;
                while bs.as_ptr() as usize != candidate_ptr {
                    // Update depth
                    let left = bs.borrow().left_child_node.clone();
                    let right = bs.borrow().right_child_node.clone();
                    let new_depth = compute_depth(&left, &right);
                    bs.borrow_mut().depth = new_depth;

                    let balance = bostree_balance(&bs);
                    if balance > 1 {
                        // Rotate left. Check for right-left case.
                        let right_child = bs.borrow().right_child_node.clone().unwrap();
                        if bostree_balance(&right_child) < 0 {
                            rotate_right(self, &right_child);
                        }
                        bs = rotate_left(self, &bs);
                    } else if balance < -1 {
                        // Rotate right. Check for left-right case.
                        let left_child = bs.borrow().left_child_node.clone().unwrap();
                        if bostree_balance(&left_child) > 0 {
                            rotate_left(self, &left_child);
                        }
                        bs = rotate_right(self, &bs);
                    }

                    // Move up
                    let parent_weak = bs.borrow().parent_node.clone();
                    bs = parent_weak.and_then(|pw| pw.upgrade()).unwrap_or(candidate.clone());
                }
            }

            // Fixup candidate's depth
            let left = candidate.borrow().left_child_node.clone();
            let right = candidate.borrow().right_child_node.clone();
            candidate.borrow_mut().depth = compute_depth(&left, &right);

            // bubble_up = candidate's parent
            bubble_up = candidate.borrow().parent_node.clone().and_then(|pw| pw.upgrade());

            // Fix immediate parent node child count
            if let Some(ref bu) = bubble_up {
                if bu.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(&candidate, lc)) {
                    bu.borrow_mut().left_child_count -= 1;
                } else {
                    bu.borrow_mut().right_child_count -= 1;
                }
            }
        } else {
            // Node has children on one side only, or no children
            let node_parent = node.borrow().parent_node.clone();
            let node_is_left = is_left_child(node);

            if node_parent.is_none() {
                // Node was the root
                let child = if node.borrow().left_child_node.is_some() {
                    let left = node.borrow().left_child_node.clone();
                    if let Some(l) = left.clone() {
                        l.borrow_mut().parent_node = None;
                    }
                    left
                } else {
                    let right = node.borrow().right_child_node.clone();
                    if let Some(r) = right.clone() {
                        r.borrow_mut().parent_node = None;
                    }
                    right
                };
                self.root_node = child;
                bubble_up = None;
            } else {
                // Node has a parent
                let np = node_parent.unwrap().upgrade().unwrap();
                let child = node.borrow().left_child_node.clone().or_else(|| node.borrow().right_child_node.clone());
                let child_count = if node.borrow().left_child_node.is_some() {
                    node.borrow().left_child_count
                } else {
                    node.borrow().right_child_count
                };

                if node_is_left {
                    np.borrow_mut().left_child_node = child.clone();
                    np.borrow_mut().left_child_count = child_count;
                } else {
                    np.borrow_mut().right_child_node = child.clone();
                    np.borrow_mut().right_child_count = child_count;
                }

                if let Some(c) = child {
                    c.borrow_mut().parent_node = Some(Rc::downgrade(&np));
                }

                bubble_up = Some(np);
            }
        }

        // At this point, everything below and including bubble_start is balanced.
        // Rebalance further up.
        let mut bubbling_finished = false;
        while let Some(bu) = bubble_up.clone() {
            if !bubbling_finished {
                // Calculate updated depth for bubble_up
                let left = bu.borrow().left_child_node.clone();
                let right = bu.borrow().right_child_node.clone();
                let left_depth = left.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let right_depth = right.as_ref().map_or(0, |c| c.borrow().depth + 1);
                let new_depth = imax(left_depth, right_depth);
                let depth_changed = new_depth != bu.borrow().depth;
                bu.borrow_mut().depth = new_depth;

                // Rebalance
                let balance = bostree_balance(&bu);
                if balance < -1 {
                    let left_child = bu.borrow().left_child_node.clone().unwrap();
                    if bostree_balance(&left_child) > 0 {
                        rotate_left(self, &left_child);
                    }
                    bubble_up = Some(rotate_right(self, &bu));
                    continue;
                } else if balance > 1 {
                    let right_child = bu.borrow().right_child_node.clone().unwrap();
                    if bostree_balance(&right_child) < 0 {
                        rotate_right(self, &right_child);
                    }
                    bubble_up = Some(rotate_left(self, &bu));
                    continue;
                } else {
                    if !depth_changed {
                        bubbling_finished = true;
                    }
                }
            }

            // Update parent's child count
            let bu_parent = bu.borrow().parent_node.clone();
            if let Some(ref pw) = bu_parent {
                if let Some(pp) = pw.upgrade() {
                    if pp.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(&bu, lc)) {
                        pp.borrow_mut().left_child_count -= 1;
                    } else {
                        pp.borrow_mut().right_child_count -= 1;
                    }
                }
            }

            // Move up
            bubble_up = bu_parent.and_then(|pw| pw.upgrade());
        }

        // Mark node as invalid and unref
        node.borrow_mut().weak_ref_node_valid = 0;
        self.bostree_node_weak_unref(node);
    }

    /// Decrease the weak reference count for a node; if that was the last reference,
    /// free the node and return None; otherwise return the node.
    pub fn bostree_node_weak_unref(
        &mut self,
        node: &Rc<RefCell<BOSNode>>,
    ) -> Option<Rc<RefCell<BOSNode>>> {
        node.borrow_mut().weak_ref_count -= 1;
        if node.borrow().weak_ref_count == 0 {
            if let Some(free_fn) = self.free_function {
                free_fn(node);
            }
            // Node will be dropped when Rc ref count goes to 0
            None
        } else if node.borrow().weak_ref_node_valid != 0 {
            Some(node.clone())
        } else {
            None
        }
    }

    /// Lookup a node in the tree by its key.
    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(cur) = current {
            let cmp = (self.cmp_function)(key, &cur.borrow().key);
            if cmp == 0 {
                return Some(cur);
            } else if cmp < 0 {
                current = cur.borrow().left_child_node.clone();
            } else {
                current = cur.borrow().right_child_node.clone();
            }
        }
        None
    }

    /// Return the node at the given in-order index (starting at 0).
    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
        let mut current = self.root_node.clone();
        while let Some(cur) = current {
            let left_count = cur.borrow().left_child_count;
            if left_count <= index {
                index -= left_count;
                if index == 0 {
                    return Some(cur);
                }
                index -= 1;
                current = cur.borrow().right_child_node.clone();
            } else {
                current = cur.borrow().left_child_node.clone();
            }
        }
        None
    }

    /// Print the tree (only available in debug builds).
    #[cfg(debug_assertions)]
    pub fn bostree_print(&self) {
        if self.root_node.is_none() {
            return;
        }
        println!("digraph {{");
        println!("  ordering = out;");
        fn print_helper(node: &Rc<RefCell<BOSNode>>) {
            let n = node.borrow();
            println!(
                "  {} [label=\"\\N ({},{},{})\"];",
                n.key, n.left_child_count, n.right_child_count, n.depth
            );
            if let Some(ref pw) = n.parent_node {
                if let Some(pp) = pw.upgrade() {
                    println!("  {} -> {} [color=green];", n.key, pp.borrow().key);
                }
            }
            if let Some(left) = &n.left_child_node {
                println!("  {} -> {}", n.key, left.borrow().key);
                print_helper(left);
            }
            if let Some(right) = &n.right_child_node {
                println!("  {} -> {}", n.key, right.borrow().key);
                print_helper(right);
            }
        }
        print_helper(&self.root_node.clone().unwrap());
        println!("}}");
    }
}

/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    assert!(node.borrow().weak_ref_count < 127);
    assert!(node.borrow().weak_ref_count > 0);
    node.borrow_mut().weak_ref_count += 1;
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // If there's a right child, go right then go left as far as possible
    if node.borrow().right_child_node.is_some() {
        let mut current = node.borrow().right_child_node.clone().unwrap();
        while current.borrow().left_child_node.is_some() {
            let next = current.borrow().left_child_node.clone().unwrap();
            current = next;
        }
        return Some(current);
    }

    // Otherwise, go up until we find a parent where we came from the left
    let parent_weak = node.borrow().parent_node.clone();
    if let Some(pw) = parent_weak {
        let mut current = node.clone();
        while let Some(pp_weak) = current.borrow().parent_node.clone() {
            if let Some(pp) = pp_weak.upgrade() {
                let is_right = pp.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(&current, rc));
                if !is_right {
                    // We came from the left, so pp is the next node
                    return Some(pp);
                }
                current = pp;
            } else {
                return None;
            }
        }
    }
    None
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    // If there's a left child, go left then go right as far as possible
    if node.borrow().left_child_node.is_some() {
        let mut current = node.borrow().left_child_node.clone().unwrap();
        while current.borrow().right_child_node.is_some() {
            let next = current.borrow().right_child_node.clone().unwrap();
            current = next;
        }
        return Some(current);
    }

    // Otherwise, go up until we find a parent where we came from the right
    let parent_weak = node.borrow().parent_node.clone();
    if let Some(pw) = parent_weak {
        let mut current = node.clone();
        while let Some(pp_weak) = current.borrow().parent_node.clone() {
            if let Some(pp) = pp_weak.upgrade() {
                let is_left = pp.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(&current, lc));
                if !is_left {
                    // We came from the right, so pp is the previous node
                    return Some(pp);
                }
                current = pp;
            } else {
                return None;
            }
        }
    }
    None
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut counter = node.borrow().left_child_count;
    let mut current = node.clone();
    while current.borrow().parent_node.is_some() {
        let parent_weak = current.borrow().parent_node.clone().unwrap();
        if let Some(pp) = parent_weak.upgrade() {
            let is_right = pp.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(&current, rc));
            if is_right {
                counter += 1 + pp.borrow().left_child_count;
            }
            current = pp;
        } else {
            break;
        }
    }
    counter
}"}

