// Helper: check if a node is the left child of its parent
fn is_left_child(node: &Rc<RefCell<BOSNode>>) -> bool {
    let parent_weak = node.borrow().parent_node.clone();
    parent_weak.as_ref().and_then(|pw| pw.upgrade()).map_or(false, |pp| {
        pp.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(node, lc))
