53	// Helper: compute balance factor (right_depth - left_depth)
54	fn bostree_balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
55	    let n = node.borrow();
56	    let left_depth = n.left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
57	    let right_depth = n.right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
58	    right_depth as i32 - left_depth as i32
59	}
