88	fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
89	    // Extract all needed info from P first
90	    let l = p.borrow().left_child_node.clone().unwrap();
91	    let p_parent = p.borrow().parent_node.clone();
92	    let p_is_left = is_left_child(p);
93	
94	    // Update parent's child pointer or tree root
95	    if let Some(ref pw) = p_parent {
96	        if let Some(pp) = pw.upgrade() {
97	            if p_is_left {
98	                pp.borrow_mut().left_child_node = Some(l.clone());
99	            } else {
