210	impl BOSTree {
211	    /// Create a new tree with a mandatory comparison function and an optional free function.
212	    pub fn bostree_new(
213	        cmp_function: BOSTreeCmpFunction,
214	        free_function: Option<BOSTreeFreeFunction>,
215	    ) -> Self {
216	        BOSTree {
217	            root_node: None,
218	            cmp_function,
219	            free_function,
220	        }
221	    }
222	
223	    /// Return the number of nodes in the tree.
224	    pub fn bostree_node_count(&self) -> u32 {
225	        match &self.root_node {
226	            Some(root) => root.borrow().left_child_count + root.borrow().right_child_count + 1,
227	            None => 0,
228	        }
229	    }
230	
231	    /// Insert a new member into the tree and return the associated node.
232	    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
233	        // Create the new node
234	        let new_node = Rc::new(RefCell::new(BOSNode {
235	            left_child_count: 0,
236	            right_child_count: 0,
237	            depth: 0,
238	            left_child_node: None,
239	            right_child_node: None,
240	            parent_node: None,
241	            key,
242	            data,
243	            weak_ref_count: 1,
244	            weak_ref_node_valid: 1,
245	        }));
246	
247	        let new_key = new_node.borrow().key.clone();
248	
249	        // Find tree position to insert new node
250	        let mut parent_node: Option<Rc<RefCell<BOSNode>>> = None;
251	        let mut current = self.root_node.clone();
252	
253	        while let Some(cur) = current.clone() {
254	            let cmp = (self.cmp_function)(&new_key, &cur.borrow().key);
255	            parent_node = Some(cur.clone());
256	            if cmp < 0 {
257	                cur.borrow_mut().left_child_count += 1;
258	                current = cur.borrow().left_child_node.clone();
259	            } else {
260	                cur.borrow_mut().right_child_count += 1;
261	                current = cur.borrow().right_child_node.clone();
262	            }
263	        }
264	
265	        // Set the new node's parent
266	        new_node.borrow_mut().parent_node = parent_node.as_ref().map(|p| Rc::downgrade(p));
267	
268	        // Attach new node to parent or set as root
269	        if let Some(ref parent) = parent_node {
270	            let cmp = (self.cmp_function)(&new_key, &parent.borrow().key);
271	            if cmp < 0 {
272	                parent.borrow_mut().left_child_node = Some(new_node.clone());
273	            } else {
274	                parent.borrow_mut().right_child_node = Some(new_node.clone());
275	            }
276	        } else {
277	            // Simple case, this is the first node.
278	            self.root_node = Some(new_node.clone());
279	            return new_node;
280	        }
281	
282	        // Check if the depth changed with the new node:
283	        // It does only change if this is the first child of the parent
284	        let parent = parent_node.unwrap();
285	        let has_left = parent.borrow().left_child_node.is_some();
286	        let has_right = parent.borrow().right_child_node.is_some();
287	        let depth_changed = has_left ^ has_right;
288	
289	        if depth_changed {
290	            // Bubble the information up the tree
291	            parent.borrow_mut().depth += 1;
292	
293	            // We need to track the "current" node as we move up.
294	            // In C, the loop is: while(parent_node->parent_node) { parent_node = parent_node->parent_node; ... }
295	            // After rotation, parent_node becomes the new subtree root, and the loop continues.
296	            let mut current_node = parent;
297	
298	            while current_node.borrow().parent_node.is_some() {
299	                // Move up to parent
300	                let parent_weak = current_node.borrow().parent_node.clone().unwrap();
301	                let pp = parent_weak.upgrade().unwrap();
302	                // current_node is no longer needed; we'll work with pp
303	
304	                let new_left_depth = pp.borrow().left_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
305	                let new_right_depth = pp.borrow().right_child_node.as_ref().map_or(0, |c| c.borrow().depth + 1);
306	                let max_depth = imax(new_left_depth, new_right_depth);
