593	    /// Decrease the weak reference count for a node; if that was the last reference,
594	    /// free the node and return None; otherwise return the node.
595	    pub fn bostree_node_weak_unref(
596	        &mut self,
597	        node: &Rc<RefCell<BOSNode>>,
598	    ) -> Option<Rc<RefCell<BOSNode>>> {
599	        node.borrow_mut().weak_ref_count -= 1;
600	        if node.borrow().weak_ref_count == 0 {
601	            if let Some(free_fn) = self.free_function {
602	                free_fn(node);
603	            }
604	            // Node will be dropped when Rc ref count goes to 0
605	            None
606	        } else if node.borrow().weak_ref_node_valid != 0 {
607	            Some(node.clone())
608	        } else {
609	            None
610	        }
611	    }
