613	    /// Lookup a node in the tree by its key.
614	    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
615	        let mut current = self.root_node.clone();
616	        while let Some(cur) = current {
617	            let cmp = (self.cmp_function)(key, &cur.borrow().key);
618	            if cmp == 0 {
619	                return Some(cur);
620	            } else if cmp < 0 {
621	                current = cur.borrow().left_child_node.clone();
622	            } else {
623	                current = cur.borrow().right_child_node.clone();
624	            }
625	        }
626	        None
627	    }
