629	    /// Return the node at the given in-order index (starting at 0).
630	    pub fn bostree_select(&self, mut index: u32) -> Option<Rc<RefCell<BOSNode>>> {
631	        let mut current = self.root_node.clone();
632	        while let Some(cur) = current {
633	            let left_count = cur.borrow().left_child_count;
634	            if left_count <= index {
635	                index -= left_count;
636	                if index == 0 {
637	                    return Some(cur);
638	                }
639	                index -= 1;
640	                current = cur.borrow().right_child_node.clone();
641	            } else {
642	                current = cur.borrow().left_child_node.clone();
643	            }
644	        }
645	        None
646	    }
