689	/// Return the next node in an in-order traversal.
690	pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
691	    // If there's a right child, go right then go left as far as possible
692	    if node.borrow().right_child_node.is_some() {
693	        let mut current = node.borrow().right_child_node.clone().unwrap();
694	        while current.borrow().left_child_node.is_some() {
695	            let next = current.borrow().left_child_node.clone().unwrap();
696	            current = next;
697	        }
698	        return Some(current);
699	    }
700	
701	    // Otherwise, go up until we find a parent where we came from the left
702	    let parent_weak = node.borrow().parent_node.clone();
703	    if let Some(pw) = parent_weak {
704	        let mut current = node.clone();
705	        while let Some(pp_weak) = current.borrow().parent_node.clone() {
706	            if let Some(pp) = pp_weak.upgrade() {
707	                let is_right = pp.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(&current, rc));
708	                if !is_right {
709	                    // We came from the left, so pp is the next node
710	                    return Some(pp);
711	                }
712	                current = pp;
713	            } else {
714	                return None;
715	            }
716	        }
717	    }
718	    None
719	}
