722	pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
723	    // If there's a left child, go left then go right as far as possible
724	    if node.borrow().left_child_node.is_some() {
725	        let mut current = node.borrow().left_child_node.clone().unwrap();
726	        while current.borrow().right_child_node.is_some() {
727	            let next = current.borrow().right_child_node.clone().unwrap();
728	            current = next;
729	        }
730	        return Some(current);
731	    }
732	
733	    // Otherwise, go up until we find a parent where we came from the right
734	    let parent_weak = node.borrow().parent_node.clone();
735	    if let Some(pw) = parent_weak {
736	        let mut current = node.clone();
737	        while let Some(pp_weak) = current.borrow().parent_node.clone() {
738	            if let Some(pp) = pp_weak.upgrade() {
739	                let is_left = pp.borrow().left_child_node.as_ref().map_or(false, |lc| Rc::ptr_eq(&current, lc));
740	                if !is_left {
741	                    // We came from the right, so pp is the previous node
742	                    return Some(pp);
