753	/// Return the rank (in-order index) of the given node.
754	pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
755	    let mut counter = node.borrow().left_child_count;
756	    let mut current = node.clone();
757	    while current.borrow().parent_node.is_some() {
758	        let parent_weak = current.borrow().parent_node.clone().unwrap();
759	        if let Some(pp) = parent_weak.upgrade() {
760	            let is_right = pp.borrow().right_child_node.as_ref().map_or(false, |rc| Rc::ptr_eq(&current, rc));
761	            if is_right {
762	                counter += 1 + pp.borrow().left_child_count;
763	            }
764	            current = pp;
765	        } else {
766	            break;
767	        }
768	    }
769	    counter
